/**
 * Validation helper module.
 * Each validator returns an array of error message strings (empty = valid).
 * Compose them with validateUserBody / validateIdParam for route handlers.
 */

'use strict';

const EMAIL_REGEX = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;

/**
 * Validate a URL / route parameter that must be a positive integer id.
 * @param {*} id - raw value from req.params (always a string when from Express)
 * @returns {string[]} array of error messages
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors;
  }

  const num = Number(id);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a name field.
 * @param {*} name
 * @param {boolean} required - whether the field is mandatory
 * @returns {string[]}
 */
function validateName(name, required = true) {
  const errors = [];

  const missing = name === undefined || name === null || name === '';
  if (missing) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  if (name.length < 1 || name.length > 100) {
    errors.push('name must be between 1 and 100 characters');
  }

  return errors;
}

/**
 * Validate an email field.
 * @param {*} email
 * @param {boolean} required - whether the field is mandatory
 * @returns {string[]}
 */
function validateEmail(email, required = true) {
  const errors = [];

  const missing = email === undefined || email === null || email === '';
  if (missing) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must not exceed 254 characters');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate a user request body (name + email).
 * @param {object} body
 * @param {boolean} requireAll - true for create (all fields required),
 *                               false for partial update (only validate present fields)
 * @returns {string[]}
 */
function validateUserBody(body, requireAll = true) {
  const errors = [];

  // Reject unrecognised top-level payload types early
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    errors.push('request body must be a JSON object');
    return errors;
  }

  errors.push(...validateName(body.name, requireAll));
  errors.push(...validateEmail(body.email, requireAll));

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
};

