/**
 * validation.js
 * Reusable input validation helpers for API endpoints.
 * Each validator returns an array of error strings (empty = valid).
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validates that a value is a finite integer (or a string representation of one).
 * @param {*}      value - The value to check.
 * @param {string} field - Field name used in error messages.
 * @returns {string[]} Array of error messages (empty when valid).
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validates that a value is a non-empty string within the allowed length range.
 * @param {*}      value   - The value to check.
 * @param {string} field   - Field name used in error messages.
 * @param {number} minLen  - Minimum allowed character length (default 1).
 * @param {number} maxLen  - Maximum allowed character length (default 100).
 * @param {boolean} required - Whether the field is required (default true).
 * @returns {string[]} Array of error messages (empty when valid).
 */
function validateString(value, field, minLen = 1, maxLen = 100, required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) {
      errors.push(`"${field}" is required`);
    }
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < minLen) {
    errors.push(
      `"${field}" must be at least ${minLen} character${minLen !== 1 ? 's' : ''} long`
    );
  }

  if (trimmed.length > maxLen) {
    errors.push(`"${field}" must not exceed ${maxLen} characters`);
  }

  return errors;
}

/**
 * Validates that a value is a properly formatted email address and within the
 * RFC 5321 maximum length of 254 characters.
 * @param {*}      value    - The value to check.
 * @param {string} field    - Field name used in error messages (default 'email').
 * @param {boolean} required - Whether the field is required (default true).
 * @returns {string[]} Array of error messages (empty when valid).
 */
function validateEmail(value, field = 'email', required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';

  if (missing) {
    if (required) {
      errors.push(`"${field}" is required`);
    }
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`"${field}" must not exceed 254 characters`);
  }

  // RFC 5322-inspired regex: local@domain.tld
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(value)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators for common resource shapes
// ---------------------------------------------------------------------------

/**
 * Validates the body fields for creating a user (POST /users).
 * Requires: name, email.
 * @param {object} body - req.body
 * @returns {string[]} Aggregated list of validation errors.
 */
function validateCreateUser(body) {
  const errors = [
    ...validateString(body.name, 'name', 1, 100),
    ...validateEmail(body.email),
  ];
  return errors;
}

/**
 * Validates the body fields for updating a user (PUT /users/:id).
 * Requires: name, email.
 * @param {object} body   - req.body
 * @param {*}      paramId - The :id route parameter value.
 * @returns {string[]} Aggregated list of validation errors.
 */
function validateUpdateUser(body, paramId) {
  const errors = [
    ...validateId(paramId, 'id'),
    ...validateString(body.name, 'name', 1, 100),
    ...validateEmail(body.email),
  ];
  return errors;
}

/**
 * Validates a numeric :id route parameter.
 * @param {*} paramId - The :id route parameter value.
 * @returns {string[]} Aggregated list of validation errors.
 */
function validateResourceId(paramId) {
  return validateId(paramId, 'id');
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs the given validatorFn and short-
 * circuits with a 400 response when validation fails.
 *
 * Usage:
 *   router.post('/users', validate((req) => validateCreateUser(req.body)), handler);
 *
 * @param {function} validatorFn - Receives req; returns string[].
 * @returns {function} Express middleware (req, res, next).
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateString,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validateResourceId,
  validate,
};

