/**
 * validation.js
 * Reusable input-validation helpers for all API endpoints.
 *
 * Each primitive validator returns an array of human-readable error strings
 * (empty array = valid).  Composite validators combine primitives and are
 * called directly from route handlers.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Validates a route-parameter or body ID.
 * Accepts only strings/numbers that represent a positive integer.
 *
 * @param {*}      value    - The value to validate.
 * @param {string} [field]  - Field label used in error messages (default "id").
 * @returns {string[]} Array of error messages.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`${field} is required`);
    return errors;
  }

  // Route params arrive as strings; body values may be numbers.
  const asString = String(value);
  if (!/^\d+$/.test(asString) || Number(asString) <= 0) {
    errors.push(`${field} must be a positive integer`);
  }

  return errors;
}

/**
 * Validates a "name" string field.
 *
 * @param {*}      value    - The value to validate.
 * @param {boolean} required - Whether the field must be present.
 * @param {string} [field]  - Field label (default "name").
 * @returns {string[]} Array of error messages.
 */
function validateName(value, required = true, field = 'name') {
  const errors = [];

  const absent = value === undefined || value === null || value === '';
  if (absent) {
    if (required) errors.push(`${field} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }

  const trimmedLength = value.trim().length;
  if (trimmedLength < 1) {
    errors.push(`${field} must not be blank`);
  } else if (value.length > 100) {
    errors.push(`${field} must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validates an "email" string field.
 * Checks type, length (max 254 chars per RFC 5321), and basic format.
 *
 * @param {*}      value    - The value to validate.
 * @param {boolean} required - Whether the field must be present.
 * @param {string} [field]  - Field label (default "email").
 * @returns {string[]} Array of error messages.
 */
function validateEmail(value, required = true, field = 'email') {
  const errors = [];

  const absent = value === undefined || value === null || value === '';
  if (absent) {
    if (required) errors.push(`${field} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`${field} must be at most 254 characters`);
  }

  // RFC-5322-inspired pattern: local@domain.tld, no whitespace.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators (one per endpoint shape)
// ---------------------------------------------------------------------------

/**
 * Validates GET /users/:id  and  DELETE /users/:id.
 * Expects an Express `req.params` object.
 *
 * @param {{ id: string }} params
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUserIdParam(params) {
  const errors = validateId(params.id);
  return { valid: errors.length === 0, errors };
}

/**
 * Validates POST /users.
 * Both `name` and `email` are required.
 *
 * @param {object} body - Parsed request body.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
  return { valid: errors.length === 0, errors };
}

/**
 * Validates PUT /users/:id.
 * The `id` param is required; `name` and `email` in the body are optional
 * but validated when present.
 *
 * @param {{ id: string }} params
 * @param {object}         body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(params, body) {
  const errors = [...validateId(params.id)];

  // Validate only the fields the caller chose to send.
  if (body.name !== undefined) {
    errors.push(...validateName(body.name, true));
  }
  if (body.email !== undefined) {
    errors.push(...validateEmail(body.email, true));
  }

  // Require at least one updatable field.
  if (body.name === undefined && body.email === undefined) {
    errors.push('request body must include at least one field to update (name, email)');
  }

  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` and short-circuits
 * with a 400 response when validation fails.
 *
 * Usage:
 *   app.post('/users', validate((req) => validateCreateUser(req.body)), handler);
 *
 * @param {(req: object) => { valid: boolean, errors: string[] }} validatorFn
 * @returns {Function} Express middleware
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const result = validatorFn(req);
    if (!result.valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: result.errors,
      });
    }
    next();
  };
}

module.exports = {
  // Primitive validators (exported for unit-testing)
  validateId,
  validateName,
  validateEmail,
  // Composite validators
  validateUserIdParam,
  validateCreateUser,
  validateUpdateUser,
  // Middleware factory
  validate,
};

