// Reusable validation helpers for API request inputs.
// Each function returns an array of error strings.
// An empty array means the input is valid.

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a URL/route :id parameter.
 * Accepts a raw string from req.params and requires it to be a positive integer.
 *
 * @param {string} rawId  - The raw string value from req.params.id
 * @returns {string[]}    - Validation error messages (empty = valid)
 */
function validateId(rawId) {
  const errors = [];

  if (rawId === undefined || rawId === null || rawId === '') {
    errors.push('id is required');
    return errors; // No point in further checks
  }

  const parsed = Number(rawId);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a user request body.
 * Checks presence, type, format, and length constraints for `name` and `email`.
 *
 * @param {object}  body              - The parsed request body (req.body)
 * @param {object}  [options]
 * @param {boolean} [options.requireAll=true]  - When true, missing fields are an error.
 *                                               Set to false for partial-update (PATCH) semantics.
 * @returns {string[]}  - Validation error messages (empty = valid)
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];
  const { name, email } = body ?? {};

  // --- name ---
  if (name === undefined || name === null) {
    if (requireAll) {
      errors.push('name is required');
    }
  } else {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.length < 1) {
      errors.push('name must be at least 1 character');
    } else if (name.length > 100) {
      errors.push('name must be at most 100 characters');
    }
  }

  // --- email ---
  if (email === undefined || email === null) {
    if (requireAll) {
      errors.push('email is required');
    }
  } else {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (email.length > 254) {
      errors.push('email must be at most 254 characters');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    }
  }

  return errors;
}

module.exports = { validateId, validateUserBody };

