// validation.js — reusable input validation helpers

/**
 * Validate a user ID from a URL parameter.
 * Accepts only strings that represent whole, positive integers.
 *
 * @param {string} raw - the raw route param string (e.g. req.params.id)
 * @returns {{ errors: string[], value: number|null }}
 */
function validateUserId(raw) {
  const errors = [];

  if (raw === undefined || raw === null || raw === '') {
    errors.push('id is required');
    return { errors, value: null };
  }

  // Must be a whole-number string (no decimals, no sign characters beyond optional leading digits)
  if (!/^\d+$/.test(String(raw))) {
    errors.push('id must be a positive integer');
    return { errors, value: null };
  }

  const value = Number(raw);
  if (!Number.isInteger(value) || value <= 0) {
    errors.push('id must be a positive integer');
    return { errors, value: null };
  }

  return { errors, value };
}

/**
 * Validate a user name field.
 *
 * Rules:
 *   - Must be present (non-empty string after trimming)
 *   - Must be a string type
 *   - Length: 1–100 characters (after trimming)
 *
 * @param {*} name
 * @returns {{ errors: string[], value: string|null }}
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return { errors, value: null };
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return { errors, value: null };
  }

  const trimmed = name.trim();

  if (trimmed.length === 0) {
    errors.push('name must not be empty');
    return { errors, value: null };
  }

  if (trimmed.length > 100) {
    errors.push('name must be 100 characters or fewer');
    return { errors, value: null };
  }

  return { errors, value: trimmed };
}

/**
 * Validate an email address field.
 *
 * Rules:
 *   - Must be present
 *   - Must be a string type
 *   - Must match a standard email pattern (local@domain.tld)
 *   - Maximum 254 characters (RFC 5321 limit)
 *
 * @param {*} email
 * @returns {{ errors: string[], value: string|null }}
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return { errors, value: null };
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return { errors, value: null };
  }

  const trimmed = email.trim();

  if (trimmed.length === 0) {
    errors.push('email must not be empty');
    return { errors, value: null };
  }

  if (trimmed.length > 254) {
    errors.push('email must be 254 characters or fewer');
    return { errors, value: null };
  }

  // RFC 5322–inspired pattern: validates presence of local part, @, and domain with TLD
  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailPattern.test(trimmed)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
    return { errors, value: null };
  }

  return { errors, value: trimmed };
}

/**
 * Validate the full body for creating a user (POST /users).
 * All fields are required.
 *
 * @param {object} body - req.body
 * @returns {{ errors: string[], value: { name: string, email: string }|null }}
 */
function validateCreateUser(body) {
  const allErrors = [];

  const { errors: nameErrors, value: name } = validateName(body.name);
  allErrors.push(...nameErrors);

  const { errors: emailErrors, value: email } = validateEmail(body.email);
  allErrors.push(...emailErrors);

  if (allErrors.length > 0) {
    return { errors: allErrors, value: null };
  }

  return { errors: [], value: { name, email } };
}

/**
 * Validate the full body for updating a user (PUT /users/:id).
 * At least one of name or email must be provided; each provided field
 * is fully validated.
 *
 * @param {object} body - req.body
 * @returns {{ errors: string[], value: { name?: string, email?: string }|null }}
 */
function validateUpdateUser(body) {
  const allErrors = [];
  const value = {};

  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    return {
      errors: ['at least one field (name, email) must be provided for update'],
      value: null,
    };
  }

  if (hasName) {
    const { errors: nameErrors, value: name } = validateName(body.name);
    allErrors.push(...nameErrors);
    if (name !== null) value.name = name;
  }

  if (hasEmail) {
    const { errors: emailErrors, value: email } = validateEmail(body.email);
    allErrors.push(...emailErrors);
    if (email !== null) value.email = email;
  }

  if (allErrors.length > 0) {
    return { errors: allErrors, value: null };
  }

  return { errors: [], value };
}

module.exports = {
  validateUserId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

