/**
 * Validation helper module.
 *
 * Every function returns an array of human-readable error strings.
 * An empty array means the value is valid.
 */

// RFC 5321 / 5322 compliant-ish regex; catches the most common malformed addresses.
const EMAIL_REGEX =
  /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

/**
 * Checks that every field in `fields` is present (non-null, non-undefined) on `data`.
 *
 * @param {object}   data   - Object to inspect (typically req.body or req.params).
 * @param {string[]} fields - Names of required fields.
 * @returns {string[]} Error messages for each missing field.
 */
function validateRequired(data, fields) {
  return fields
    .filter(field => data[field] === undefined || data[field] === null)
    .map(field => `"${field}" is required`);
}

/**
 * Validates that `id` is a positive integer.
 * Accepts both numeric values and numeric strings (e.g. route params).
 *
 * @param {*} id
 * @returns {string[]}
 */
function validateId(id) {
  const num = Number(id);
  if (!Number.isInteger(num) || num <= 0) {
    return ['"id" must be a positive integer'];
  }
  return [];
}

/**
 * Validates a name value: must be a string between 1 and 100 characters.
 *
 * @param {*} name
 * @returns {string[]}
 */
function validateName(name) {
  const errors = [];
  if (typeof name !== 'string') {
    errors.push('"name" must be a string');
    return errors; // further length checks are meaningless
  }
  if (name.length < 1) errors.push('"name" must be at least 1 character long');
  if (name.length > 100) errors.push('"name" must be at most 100 characters long');
  return errors;
}

/**
 * Validates an email value: must be a string, match the email format, and be
 * at most 254 characters (RFC 5321 maximum).
 *
 * @param {*} email
 * @returns {string[]}
 */
function validateEmail(email) {
  const errors = [];
  if (typeof email !== 'string') {
    errors.push('"email" must be a string');
    return errors; // further checks are meaningless
  }
  if (email.length > 254) errors.push('"email" must be at most 254 characters long');
  if (!EMAIL_REGEX.test(email)) errors.push('"email" must be a valid email address');
  return errors;
}

/**
 * Validates a user request body.
 *
 * Strategy:
 *   1. Check that every field listed in `requiredFields` is present.
 *   2. For each field that IS present, run the appropriate type/format/length
 *      checks.  Fields that failed the required check are skipped to avoid
 *      duplicate errors.
 *
 * @param {object}   body                          - req.body
 * @param {string[]} [requiredFields=['name','email']] - Fields that must be present.
 * @returns {string[]} Combined list of all validation errors (empty = valid).
 */
function validateUserBody(body, requiredFields = ['name', 'email']) {
  const errors = [];
  const missingFields = new Set();

  // --- 1. Required-field presence ---
  for (const field of requiredFields) {
    if (body[field] === undefined || body[field] === null) {
      errors.push(`"${field}" is required`);
      missingFields.add(field);
    }
  }

  // --- 2. Type / format / length checks (only for fields that are present) ---
  if (!missingFields.has('name') && body.name !== undefined) {
    errors.push(...validateName(body.name));
  }
  if (!missingFields.has('email') && body.email !== undefined) {
    errors.push(...validateEmail(body.email));
  }

  return errors;
}

module.exports = {
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
};

