/**
 * Validation helper module.
 *
 * Each exported function returns an array of error message strings.
 * An empty array means all checks passed.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Returns an error message if `value` is absent (undefined, null, or
 * empty-string after trimming), otherwise returns null.
 */
function validateRequired(fieldName, value) {
  if (value === undefined || value === null || String(value).trim() === '') {
    return `"${fieldName}" is required`;
  }
  return null;
}

/**
 * Returns an error message if `value` is not a finite integer > 0.
 * Accepts numbers and numeric strings.
 */
function validateNumericId(fieldName, value) {
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    return `"${fieldName}" must be a positive integer`;
  }
  return null;
}

/**
 * Returns an error message if `value` is not a non-empty string.
 */
function validateString(fieldName, value) {
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  return null;
}

/**
 * Returns an error message if `value` length is outside [min, max].
 * Assumes `value` is already confirmed to be a string.
 */
function validateStringLength(fieldName, value, min, max) {
  if (typeof value !== 'string') return null; // type error already reported
  if (value.length < min || value.length > max) {
    return `"${fieldName}" must be between ${min} and ${max} characters`;
  }
  return null;
}

/**
 * Returns an error message if `value` does not look like a valid e-mail
 * address per RFC 5321 / common convention.
 */
function validateEmail(fieldName, value) {
  if (typeof value !== 'string') return null; // type error already reported
  // Local part + @ + domain; domain must have at least one dot
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `"${fieldName}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Composite field validators
// ---------------------------------------------------------------------------

/**
 * Validates `id` from route params.
 * Rules: required, numeric (positive integer).
 * @param {string|number} id
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateId(id) {
  const errors = [];
  const req = validateRequired('id', id);
  if (req) { errors.push(req); return errors; }
  const num = validateNumericId('id', id);
  if (num) errors.push(num);
  return errors;
}

/**
 * Validates a `name` field.
 * Rules: required, string type, 1–100 chars.
 * @param {*} name
 * @returns {string[]}
 */
function validateName(name) {
  const errors = [];
  const req = validateRequired('name', name);
  if (req) { errors.push(req); return errors; }
  const typeErr = validateString('name', name);
  if (typeErr) { errors.push(typeErr); return errors; }
  const lenErr = validateStringLength('name', name.trim(), 1, 100);
  if (lenErr) errors.push(lenErr);
  return errors;
}

/**
 * Validates an `email` field.
 * Rules: required, string type, valid email format, max 254 chars.
 * @param {*} email
 * @returns {string[]}
 */
function validateEmailField(email) {
  const errors = [];
  const req = validateRequired('email', email);
  if (req) { errors.push(req); return errors; }
  const typeErr = validateString('email', email);
  if (typeErr) { errors.push(typeErr); return errors; }
  const lenErr = validateStringLength('email', email, 1, 254);
  if (lenErr) errors.push(lenErr);
  const fmtErr = validateEmail('email', email);
  if (fmtErr) errors.push(fmtErr);
  return errors;
}

// ---------------------------------------------------------------------------
// Request-level validators (combine field validators for a whole body/params)
// ---------------------------------------------------------------------------

/**
 * Validates route param object for endpoints that require a numeric `:id`.
 * @param {{ id?: * }} params  Express req.params
 * @returns {string[]}
 */
function validateUserParams(params) {
  return validateId(params.id);
}

/**
 * Validates the request body for POST /users (create).
 * Both `name` and `email` are required.
 * @param {{ name?: *, email?: * }} body  Express req.body
 * @returns {string[]}
 */
function validateCreateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmailField(body.email),
  ];
}

/**
 * Validates the request body for PUT /users/:id (full update).
 * Both `name` and `email` must be present.
 * @param {{ name?: *, email?: * }} body  Express req.body
 * @returns {string[]}
 */
function validateUpdateUserBody(body) {
  return validateCreateUserBody(body); // same rules for full replacement
}

/**
 * Validates the request body for PATCH /users/:id (partial update).
 * At least one of `name` or `email` must be supplied; supplied fields are
 * validated individually.
 * @param {{ name?: *, email?: * }} body  Express req.body
 * @returns {string[]}
 */
function validatePatchUserBody(body) {
  const errors = [];
  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one of "name" or "email" must be provided');
    return errors;
  }
  if (hasName)  errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmailField(body.email));
  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware that runs `validatorFn` against the chosen
 * source (`'body'`, `'params'`, or `'query'`).  If validation fails the
 * middleware responds with 400 and a JSON error object listing every failure.
 * Otherwise it calls `next()`.
 *
 * @param {function(*): string[]} validatorFn
 * @param {'body'|'params'|'query'} [source='body']
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    const errors = validatorFn(req[source]);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Primitive validators (useful for unit-testing or custom composition)
  validateRequired,
  validateNumericId,
  validateString,
  validateStringLength,
  validateEmail,

  // Field-level validators
  validateId,
  validateName,
  validateEmailField,

  // Request-level validators
  validateUserParams,
  validateCreateUserBody,
  validateUpdateUserBody,
  validatePatchUserBody,

  // Middleware factory
  validate,
};
